SELECT total_cases
FROM influenza_data
WHERE year = 2009 AND country_id = 0;

SELECT SUM(total_cases) AS total_influenza_cases
FROM influenza_data
WHERE year = 2009 AND week = 1;

SELECT COUNT(influenza_case_id) AS total_cases
FROM influenza_cases
WHERE date_of_onset BETWEEN '2009-01-05' AND '2009-01-11';

SELECT COUNT(*) AS death_count
FROM hospitalization_data
WHERE outcome = 'Died' AND hospital_name = 'County Hospital';

SELECT DISTINCT wr.who_region_name
FROM influenza_data id
JOIN who_regions wr ON id.who_region_id = wr.who_region_id;
